"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Plus, Edit, Trash2, MapPin, Users, Search, Filter, ArrowLeft } from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { Pagination } from "@/components/pagination";
import api from "@/lib/axios";
import { deleteField } from "@/lib/api/fields";

export default function OwnerFieldsPage() {
  const [fields, setFields] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState("");
  const [statusFilter, setStatusFilter] = useState("all");
  const [deleteDialog, setDeleteDialog] = useState<number | null>(null);
  const { toast } = useToast();
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 6;

  //  BASE URL BACKEND
  const API_URL = process.env.NEXT_PUBLIC_API_URL || "http://localhost:8000";

  // ============================
  // FETCH FIELDS FROM BACKEND
  // ============================
  useEffect(() => {
    async function load() {
      try {
        const token = localStorage.getItem("token");
        const res = await api.get("/owner/fields", {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        });

        setFields(res.data.data || []);
      } catch (err) {
        console.error(err);
        toast({
          title: "Không thể tải danh sách sân",
          description: "Vui lòng thử lại sau.",
          variant: "destructive",
        });
      } finally {
        setLoading(false);
      }
    }

    load();
  }, []);

  // ============================
  // FILTERING
  // ============================
  const filteredFields = fields.filter((field) => {
    const name = field.field_name?.toLowerCase() || "";
    const matchesSearch = name.includes(searchQuery.toLowerCase());
    const matchesStatus = statusFilter === "all" || field.status === statusFilter;
    return matchesSearch && matchesStatus;
  });

  const totalPages = Math.ceil(filteredFields.length / itemsPerPage);
  const paginatedFields = filteredFields.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage);

  // const handleDelete = (id: number) => {
  //   // todo: call delete api here
  //   setFields(fields.filter((f) => f.id !== id));
  //   setDeleteDialog(null);
  //   toast({
  //     title: "Đã xóa sân",
  //     description: "Sân đã được xóa khỏi danh sách.",
  //   });
  // };
  const handleDelete = async (id: number) => {
  try {
    const token = localStorage.getItem("token")!;

    await deleteField(id, token);

    // Xóa trên FE
    setFields(fields.filter((f) => f.id !== id));

    toast({
      title: "Đã xóa sân",
      description: "Sân đã được xóa khỏi hệ thống.",
    });
  } catch (err) {
    console.error(err);
    toast({
      title: "Xóa thất bại",
      description: "Không thể xóa sân. Vui lòng thử lại.",
      variant: "destructive",
    });
  }

  setDeleteDialog(null);
};

  // ============================
  // LOADING
  // ============================
  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center text-lg">
        Đang tải danh sách sân...
      </div>
    );
  }

  return (
    <main className="min-h-screen bg-background">
      {/* Header */}
      <header className="sticky top-0 z-50 bg-background border-b border-border">
        <div className="max-w-7xl mx-auto px-4 py-4 flex items-center justify-between">
          <Link href="/owner/dashboard" className="flex items-center gap-2 text-primary hover:text-primary/80">
            <ArrowLeft className="w-5 h-5" />
            Quay lại
          </Link>
          <h1 className="text-xl font-bold">Quản Lý Sân</h1>
          <Link href="/owner/fields/new">
            <Button>
              <Plus className="w-4 h-4 mr-2" />
              Thêm Sân
            </Button>
          </Link>
        </div>
      </header>

      <div className="max-w-7xl mx-auto px-4 py-8">
        {/* Search + Filter */}
        <Card className="p-4">
          <div className="flex flex-col md:flex-row gap-4">
            <div className="flex-1 relative">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
              <Input
                placeholder="Tìm kiếm sân..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="pl-10"
              />
            </div>

            <Select value={statusFilter} onValueChange={setStatusFilter}>
              <SelectTrigger className="w-full md:w-[200px]">
                <Filter className="w-4 h-4 mr-2" />
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">Tất cả trạng thái</SelectItem>
                <SelectItem value="active">Hoạt động</SelectItem>
                <SelectItem value="inactive">Không hoạt động</SelectItem>
                <SelectItem value="pending">Chờ duyệt</SelectItem>
              </SelectContent>
            </Select>

            <Link href="/owner/fields/new">
              <Button>
                <Plus className="w-4 h-4 mr-2" />
                Thêm Sân
              </Button>
            </Link>
          </div>
        </Card>

        <div className="text-sm text-muted-foreground mb-4">
          Hiển thị {filteredFields.length} / {fields.length} sân
        </div>

        {/* FIELD LIST */}
        <div className="space-y-4 mb-8">
          {paginatedFields.map((field) => {
            const rawUrl = field.field_images?.[0]?.url;

            // FIX PATH WINDOWS + BASE URL
            const imageUrl = rawUrl
              ? `${API_URL}/${rawUrl.replace(/\\/g, "/")}`
              : "/placeholder.svg";

            return (
              <Card key={field.id} className="overflow-hidden">
                <div className="flex flex-col md:flex-row">
                  <img
                    src={imageUrl}
                    alt={field.field_name}
                    className="w-full md:w-48 h-48 object-cover"
                  />

                  <div className="flex-1 p-6 flex flex-col justify-between">
                    <div>
                      <div className="flex items-start justify-between mb-4">
                        <div>
                          <h3 className="text-xl font-bold text-foreground mb-1">
                            {field.field_name}
                          </h3>

                          <div className="flex items-center gap-1 text-sm text-muted-foreground">
                            <MapPin className="w-4 h-4" />
                            {field.address}
                          </div>
                        </div>

                        <span
                          className={`px-3 py-1 rounded-full text-sm font-medium ${
                            field.status === "active"
                              ? "bg-green-100 text-green-700 dark:bg-green-900 dark:text-green-300"
                              : "bg-gray-100 text-gray-700 dark:bg-gray-800 dark:text-gray-300"
                          }`}
                        >
                          {field.status === "active" ? "Hoạt Động" : "Không Hoạt Động"}
                        </span>
                      </div>

                      <div className="grid grid-cols-3 gap-4 mb-4">
                        <div>
                          <p className="text-xs text-muted-foreground">Loại</p>
                          <p className="font-medium text-foreground">
                            {field.sport_type}
                          </p>
                        </div>

                        <div>
                          <p className="text-xs text-muted-foreground">Sức Chứa</p>
                          <p className="font-medium text-foreground flex items-center gap-1">
                            <Users className="w-4 h-4" />
                            {field.max_players || "--"} người
                          </p>
                        </div>

                        <div>
                          <p className="text-xs text-muted-foreground">Giá</p>
                          <p className="font-medium text-foreground">
                            {Number(field.base_price_per_hour).toLocaleString()} VND/giờ
                          </p>
                        </div>
                      </div>
                    </div>

                    <div className="flex gap-2 pt-4 border-t border-border">
                      <Link href={`/owner/fields/${field.id}/edit`}>
                        <Button variant="outline" size="sm">
                          <Edit className="w-4 h-4 mr-2" />
                          Sửa
                        </Button>
                      </Link>

                      <Button
                        variant="outline"
                        size="sm"
                        className="text-destructive bg-transparent"
                        onClick={() => setDeleteDialog(field.id)}
                      >
                        <Trash2 className="w-4 h-4 mr-2" />
                        Xóa
                      </Button>
                    </div>
                  </div>
                </div>
              </Card>
            );
          })}
        </div>

        {/* EMPTY STATE */}
        {fields.length === 0 && (
          <Card className="p-12 text-center">
            <p className="text-muted-foreground text-lg mb-4">Chưa có sân nào</p>
            <Link href="/owner/fields/new">
              <Button>
                <Plus className="w-4 h-4 mr-2" />
                Thêm Sân Đầu Tiên
              </Button>
            </Link>
          </Card>
        )}

        {/* PAGINATION */}
        {filteredFields.length > 0 && (
          <Pagination
            currentPage={currentPage}
            totalPages={totalPages}
            onPageChange={setCurrentPage}
            itemsPerPage={itemsPerPage}
            totalItems={filteredFields.length}
          />
        )}
      </div>

      {/* DELETE DIALOG */}
      <Dialog open={deleteDialog !== null} onOpenChange={() => setDeleteDialog(null)}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Xác nhận xóa sân</DialogTitle>
            <DialogDescription>
              Bạn có chắc chắn muốn xóa sân này? Hành động này không thể hoàn tác.
            </DialogDescription>
          </DialogHeader>

          <DialogFooter>
            <Button variant="outline" onClick={() => setDeleteDialog(null)}>
              Hủy
            </Button>
            <Button variant="destructive" onClick={() => deleteDialog && handleDelete(deleteDialog)}>
              Xác Nhận Xóa
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </main>
  );
}
